+              })),
+            };
+          }
+          if (table === "skills") {
+            return {
+              withIndex: vi.fn((indexName: string) => {
+                if (indexName === "by_owner_publisher") {
+                  return {
+                    order: vi.fn(() => ({
+                      take: vi.fn().mockResolvedValue([]),
+                    })),
+                  };
+                }
